import java.util.*;

class LFUCache {
    private final int capacity;
    private int minFreq;
    private final Map<Integer, Node> keyMap;
    private final Map<Integer, LinkedHashSet<Node>> freqMap;

    private static class Node {
        int key, val, freq;
        Node(int k, int v) {
            key = k;
            val = v;
            freq = 1;
        }
    }

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.minFreq = 0;
        this.keyMap = new HashMap<>();
        this.freqMap = new HashMap<>();
    }

    public int get(int key) {
        if (capacity == 0) return -1;
        Node node = keyMap.get(key);
        if (node == null) return -1;
        update(node);
        return node.val;
    }

    public void put(int key, int value) {
        if (capacity == 0) return;
        Node node = keyMap.get(key);
        if (node != null) {
            node.val = value;
            update(node);
            return;
        }
        if (keyMap.size() == capacity) {
            LinkedHashSet<Node> set = freqMap.get(minFreq);
            Node toEvict = set.iterator().next();
            set.remove(toEvict);
            keyMap.remove(toEvict.key);
            if (set.isEmpty()) freqMap.remove(minFreq);
        }
        Node newNode = new Node(key, value);
        keyMap.put(key, newNode);
        freqMap.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(newNode);
        minFreq = 1;
    }

    private void update(Node node) {
        LinkedHashSet<Node> oldSet = freqMap.get(node.freq);
        oldSet.remove(node);
        if (oldSet.isEmpty()) {
            freqMap.remove(node.freq);
            if (minFreq == node.freq) minFreq++;
        }
        node.freq++;
        freqMap.computeIfAbsent(node.freq, k -> new LinkedHashSet<>()).add(node);
    }
}
```
efficiency: HIGH
time complexity: O(1) average for both get and put
space complexity: O(capacity)
energy implications: MEDIUM
explanation: Uses two hash maps: keyMap for O(1) node access and freqMap for O(1) frequency buckets. Each bucket is a LinkedHashSet preserving insertion order for LRU tie-breaking. On access, a node is moved to the next frequency bucket in O(1). Eviction removes the first node from the lowest frequency bucket.

